class SQSWorker:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time: int = 20,
        visibility_timeout: int = 30,
        max_workers: int = 5
    ):
        self.queue_url = queue_url
        self.max_messages = max_messages
        self.wait_time = wait_time
        self.visibility_timeout = visibility_timeout
        self.max_workers = max_workers
        self.running = False
        
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        self.message_processor = MessageProcessor()
        self.executor = ThreadPoolExecutor(max_workers=max_workers)
        
        logger.info(f"Initialized SQS Worker for queue: {queue_url}")
    
    def register_custom_handler(self, message_type: str, handler: MessageHandler):
        self.message_processor.register_handler(message_type, handler)
    
    def poll_messages(self):
        try:
            response = self.sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time,
                VisibilityTimeout=self.visibility_timeout,
                MessageAttributeNames=['All'],
                AttributeNames=['All']
            )
            
            messages = response.get('Messages', [])
            logger.info(f"Received {len(messages)} messages from queue")
            return messages
        
        except Exception as e:
            logger.error(f"Error polling messages: {str(e)}")
            logger.error(traceback.format_exc())
            return []
    
    def parse_message(self, message: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            body = message.get('Body', '{}')
            
            try:
                parsed_body = json.loads(body)
            except json.JSONDecodeError:
                parsed_body = {'raw_body': body}
            
            message_type = parsed_body.get('type', 'default')
            
            message_attributes = message.get('MessageAttributes', {})
            if 'type' in message_attributes:
                message_type = message_attributes['type'].get('StringValue', message_type)
            
            return {
                'message_id': message.get('MessageId'),
                'receipt_handle': message.get('ReceiptHandle'),
                'type': message_type,
                'body': parsed_body,
                'attributes': message.get('Attributes', {}),
                'message_attributes': message_attributes
            }
        
        except Exception as e:
            logger.error(f"Error parsing message: {str(e)}")
            logger.error(traceback.format_exc())
            return None
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        try:
            parsed_message = self.parse_message(message)
            
            if not parsed_message:
                logger.error("Failed to parse message")
                return False
            
            logger.info(f"Processing message {parsed_message['message_id']} of type {parsed_message['type']}")
            
            success = self.message_processor.process(
                parsed_message['type'],
                parsed_message['body']
            )
            
            if success:
                self.delete_message(parsed_message['receipt_handle'])
                logger.info(f"Successfully processed and deleted message {parsed_message['message_id']}")
            else:
                logger.error(f"Failed to process message {parsed_message['message_id']}")
            
            return success
        
        except Exception as e:
            logger.error(f"Error processing message: {str(e)}")
            logger.error(traceback.format_exc())
            return False
    
    def delete_message(self, receipt_handle: str):
        try:
            self.sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info("Message deleted from queue")
        
        except Exception as e:
            logger.error(f"Error deleting message: {str(e)}")
            logger.error(traceback.format_exc())
    
    def change_message_visibility(self, receipt_handle: str, timeout: int):
        try:
            self.sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout
            )
            logger.info(f"Changed message visibility timeout to {timeout} seconds")
        
        except Exception as e:
            logger.error(f"Error changing message visibility: {str(e)}")
    
    def process_messages_batch(self, messages):
        futures = []
        for message in messages:
            future = self.executor.submit(self.process_message, message)
            futures.append(future)
        
        for future in futures:
            try:
                future.result()
            except Exception as e:
                logger.error(f"Error in message processing: {str(e)}")
    
    def start(self, polling_interval: int = 0):
        self.running = True
        logger.info("Starting SQS Worker...")
        
        while self.running:
            try:
                messages = self.poll_messages()
                
                if messages:
                    self.process_messages_batch(messages)
                else:
                    logger.info("No messages received")
                
                if polling_interval > 0 and self.running:
                    time.sleep(polling_interval)
            
            except KeyboardInterrupt:
                logger.info("Received shutdown signal")
                self.stop()
            
            except Exception as e:
                logger.error(f"Error in main loop: {str(e)}")
                logger.error(traceback.format_exc())
                time.sleep(5)
    
    def stop(self):
        logger.info("Stopping SQS Worker...")
        self.running = False
        self.executor.shutdown(wait=True)
        logger.info("SQS Worker stopped")


class AdvancedSQSWorker(SQSWorker):
    def __init__(self, *args, **kwargs):
        self.dlq_url = kwargs.pop('dlq_url', None)
        self.max_retries = kwargs.pop('max_retries', 3)
        super().__init__(*args, **kwargs)
    
    def process_message(self, message: Dict[str, Any]) -> bool:
        parsed_message = self.parse_message(message)
        
        if not parsed_message:
            if self.dlq_url:
                self.send_to_dlq(message)
            return False
        
        retry_count = int(parsed_message['attributes'].get('ApproximateReceiveCount', 1))
        
        if retry_count > self.max_retries:
            logger.warning(f"Message {parsed_message['message_id']} exceeded max retries")
            if self.dlq_url:
                self.send_to_dlq(message)
            self.delete_message(parsed_message['receipt_handle'])
            return False
        
        try:
            success = self.message_processor.process(
                parsed_message['type'],
                parsed_message['body']
            )
            
            if success:
                self.delete_message(parsed_message['receipt_handle'])
                logger.info(f"Successfully processed message {parsed_message['message_id']}")
                return True
            else:
                logger.error(f"Failed to process message {parsed_message['message_id']}, will retry")
                return False
        
        except Exception as e:
            logger.error(f"Exception processing message: {str(e)}")
            logger.error(traceback.format_exc())
            
            if retry_count >= self.max_retries:
                if self.dlq_url:
                    self.send_to_dlq(message)
                self.delete_message(parsed_message['receipt_handle'])
            
            return False
    
    def send_to_dlq(self, message: Dict[str, Any]):
        try:
            self.sqs_client.send_message(
                QueueUrl=self.dlq_url,
                MessageBody=message.get('Body'),
                MessageAttributes=message.get('MessageAttributes', {})
            )
            logger.info(f"Sent message {message.get('MessageId')} to DLQ")
        
        except Exception as e:
            logger.error(f"Error sending message to DLQ: {str(e)}")


